// // This is a 1-to-4 demultiplexer that outputs one of four 4-bit wide inputs based on a 2-bit select signal.
module top_module(
    input [3:0] A, B, C, D,
    input [1:0] S,
    output reg [3:0] OUT
);always @(*) begin
    case(S)
        2'b00: OUT = A;
        2'b01: OUT = B;
        2'b10: OUT = C;
        2'b11: OUT = D;
    endcase
end

endmodule
